// RegisterDebugger adds every generated Debugger tool to the registry.
func RegisterDebugger(r *tools.Registry) {
	r.MustRegister(NewDebuggerContinueToLocation())
	r.MustRegister(NewDebuggerDisassembleWasmModule())
	r.MustRegister(NewDebuggerEvaluateOnCallFrame())
	r.MustRegister(NewDebuggerGetPossibleBreakpoints())
	r.MustRegister(NewDebuggerGetScriptSource())
	r.MustRegister(NewDebuggerGetStackTrace())
	r.MustRegister(NewDebuggerGetWasmBytecode())
	r.MustRegister(NewDebuggerNextWasmDisassemblyChunk())
	r.MustRegister(NewDebuggerPause())
	r.MustRegister(NewDebuggerPauseOnAsyncCall())
	r.MustRegister(NewDebuggerRemoveBreakpoint())
	r.MustRegister(NewDebuggerRestartFrame())
	r.MustRegister(NewDebuggerResume())
	r.MustRegister(NewDebuggerSearchInContent())
	r.MustRegister(NewDebuggerSetAsyncCallStackDepth())
	r.MustRegister(NewDebuggerSetBlackboxExecutionContexts())
	r.MustRegister(NewDebuggerSetBlackboxPatterns())
	r.MustRegister(NewDebuggerSetBlackboxedRanges())
	r.MustRegister(NewDebuggerSetBreakpoint())
	r.MustRegister(NewDebuggerSetBreakpointByUrl())
	r.MustRegister(NewDebuggerSetBreakpointOnFunctionCall())
	r.MustRegister(NewDebuggerSetBreakpointsActive())
	r.MustRegister(NewDebuggerSetInstrumentationBreakpoint())
	r.MustRegister(NewDebuggerSetPauseOnExceptions())
	r.MustRegister(NewDebuggerSetReturnValue())
	r.MustRegister(NewDebuggerSetScriptSource())
	r.MustRegister(NewDebuggerSetSkipAllPauses())
	r.MustRegister(NewDebuggerSetVariableValue())
	r.MustRegister(NewDebuggerStepInto())
	r.MustRegister(NewDebuggerStepOut())
	r.MustRegister(NewDebuggerStepOver())
}
